#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int A, B; scanf("%d %d", &A, &B);
        int price1 = 100 - A;
        int price2 = 200 - 2 * B;
        if(price1 < price2) printf("FIRST\n");
        else if(price1 > price2) printf("SECOND\n");
        else printf("BOTH\n");
    }
    return 0;
}

