import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    idx = 1
    out = []
    for _ in range(t):
        A = int(data[idx]); B = int(data[idx+1]); idx += 2
        price1 = 100 - A
        price2 = 200 - 2 * B
        if price1 < price2:
            out.append('FIRST')
        elif price1 > price2:
            out.append('SECOND')
        else:
            out.append('BOTH')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

